const Q_ACCOUNTS_2019_MODEL_II=[{"id": "objective>Accounts>2019 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Majority of commercial transactions are termed credit transactions, which means </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The buyers pay immediately for goods bought</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Settlement is deferred to a future date </div>", "<div style=\"font-family:Cambria;font-size:17px;\">No account will be opened </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Item of expenditure increases </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In credit transactions, the transfer of ownership takes place before payment to the supplier i.e settlement is at a future safe.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>2019 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bought motor vehicle ₦60 paying by cheque. The effect of the transaction will be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase in assets of motor vehicle account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decrease in assets of motor vehicle account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in assets of bank account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in liabilities of bank account </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The motor vehicle account is the receiver while bank account is giving out. Therefore, there will be an increase in motor account and a decrease in bank account.</div>", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL"}, {"id": "objective>Accounts>2019 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rules of double entry states that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">for every debit entry, there must be a corresponding debit entry </div>", "<div style=\"font-family:Cambria;font-size:17px;\">for every credit entry, there must be a corresponding credit entry </div>", "<div style=\"font-family:Cambria;font-size:17px;\">all transactions must be recorded in two accounts, one account is debited and another is credited</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all transaction must be credited </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Double entry system is the entry of debit and credit for each transaction in the ledger. Hence the double entry rules states that \"debit the receivers, credit the giver\".</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION"}, {"id": "objective>Accounts>2019 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between double entry and single entry is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">double entry is based on the dual concept while single entry is not based on dual concept </div>", "<div style=\"font-family:Cambria;font-size:17px;\">double entry is an account while single entry is not an account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">double entry keeps personal account while single does not </div>", "<div style=\"font-family:Cambria;font-size:17px;\">double entry is useful for business enterprise while single entry is not </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Double entry is based on dual concept, i.e two-fold aspect of transaction whereby single entry ignored the principle of double entry.</div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES"}, {"id": "objective>Accounts>2019 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rent of ₦50,000 was paid by samson to his landlady by cheque. The double entry in Samson's book is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Debit rent account, Credit bank account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debit Rent account, Credit Samson's account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debit Bank account, Credit Rent account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debit Samson's account, Credit Rent account</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the double entry bookkeeping system, when a rent is paid by cheque, the rent account is debited because it is an expense and expenses are increased by debits. The bank account is credited because the payment reduces the bank balance and assets are decreased by credits.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>2019 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The purpose of profit and loss account is to ascertain</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gross profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Expenses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Net profit</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The profit and loss account also known as Income statement is prepared to ascertain the net profit. The net profit is ascertain when the expenses is deducted from the Gross Profit.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT"}, {"id": "objective>Accounts>2019 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Discount received is charge to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">current account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit and loss </div>", "<div style=\"font-family:Cambria;font-size:17px;\">trading account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance sheet</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Discount received is a gain for the business, and it is credited to the Profit and Loss Account. Therefore, the correct answer is 'profit and loss'.</div>", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED"}, {"id": "objective>Accounts>2019 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following to answer this question <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> <br/> Opening stock <br/> Purchases <br/> Sales <br/> Closing Stocks</td><td style=\"border:1px solid black;text-align:center;\">₦ <br/> 20,000 <br/> 70,000 <br/> 100,000 <br/> 15,000</td></tr></table></div> <br/>  <br/> What was the cost of goods sold?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦25,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦35,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦50,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦75,000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost of goods sold = Opening stock + Purchases - closing stocks  <br/>  20,000 + 70,000 - 15,000 <br/> ⇒ ₦75,000</div>", "topic": "STOCK VALUATION : MEANING OF STOCK VALUATION AND METHODS"}, {"id": "objective>Accounts>2019 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the following to answer this question <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> <br/> Opening stock <br/> Purchases <br/> Sales <br/> Closing Stocks</td><td style=\"border:1px solid black;text-align:center;\">₦ <br/> 20,000 <br/> 70,000 <br/> 100,000 <br/> 15,000</td></tr></table></div> <br/> What was the gross profit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦35,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦75,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦50,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦25,000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gross profit is calculated by subtracting the cost of goods sold from the sales. In this case,  <br/>  <br/> Gross Profit = Sales - COGS = ₦100,000 - ₦75,000  <br/> = ₦25,000.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2019 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information to answer this question <br/>  <br/> Testdriller balance sheet as at 31st Dec 2018 <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The owner's equity is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦100,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦110,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦160,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦280,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Owner's equity  = 100,000 + 50,000 + 10,000 <br/> = 160,000</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET"}, {"id": "objective>Accounts>2019 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information to answer this question <br/>  <br/> Testdriller balance sheet as at 31st Dec 2018 <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Determine the liquid ratio</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5 : 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 : 5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 : 5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 : 3</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Liquid ratio also known as Acid test ratio is calculated as : <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">current assets - stock<hr size=\"1\" />current liabilities</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(12,000 + 70,000 + 18,000)<hr size=\"1\" />150,000 + 70,000</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100,000 - 12,000<hr size=\"1\" />220,000</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">88,000<hr size=\"1\" />220,000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">:</td><td style=\"text-align:center;\">5</td></tr></table></div></div>", "topic": "ACCOUNTING RATIO (2) : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO"}, {"id": "objective>Accounts>2019 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ordinary share of ₦100 was issued at ₦80. The share was issued at </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">premium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">par </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount </div>", "<div style=\"font-family:Cambria;font-size:17px;\">loss</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a share is issued at a price less than its face value, it is said to be issued at a discount. In this case, the ordinary share has a face value of ₦100 but was issued at ₦80, hence it was issued at a discount.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2019 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Shares that are offered to existing shareholders at a price is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">par </div>", "<div style=\"font-family:Cambria;font-size:17px;\">premium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">right issue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bonus issue</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Right issue refers to the issuance of shares by a company to its existing shareholders at a pre-determined price. Usually, the price at which these shares are offered is less than the current market price. This is done to raise additional capital while also giving existing shareholders the 'right' to buy new shares proportionate to their existing holdings.</div>", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS"}, {"id": "objective>Accounts>2019 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following information to answer this question <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Year</td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1991 <br/> 1992 <br/> 1993 <br/> 1994</td><td style=\"border:1px solid black;text-align:center;\">14,000 <br/> 24,000 <br/> 10,000 <br/> 16,000</td></tr></table></div> <br/>  <br/> It has been decided to value goodwill at 2 years purchase of average profit for the past 4 years. The value of goodwill is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦32,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦16,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦30,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦64,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Average</td><td style=\"text-align:center;\">profit</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">14,000 + 24,000 + 10,000 + 16,000<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">64,000<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">₦16,000</td></tr></table></div></div>", "topic": "GOODWILL ACCOUNTS : GOODWILL VALUATION"}, {"id": "objective>Accounts>2019 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Where there is no agreement made by the partners, the following provisions takes place except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">No salary for partners acting in the business </div>", "<div style=\"font-family:Cambria;font-size:17px;\">There is interest on capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">No interest to be charged on drawings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Profit and loss are to be shared equally</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to section 24 of the partnership Act 1890. If no specific agreement is made by the partners, the following takes place: <br/> -  No partners may introduce a new person without the consent of all other partners 2.5% interest a year on loans made by partner e.t.c</div>", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS( PARTNERSHIP)"}, {"id": "objective>Accounts>2019 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a non-profit making organisation, the excess of Assets over liabilities equals </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital employed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital owned </div>", "<div style=\"font-family:Cambria;font-size:17px;\">accumulated funds </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The excess of the assets over the liabilities of a non-profit making concern is called Accumulated Fund. It is the capital of a non-profit making association. In order to ascertain the accumulated fund, a statement of affairs will be prepared.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS"}, {"id": "objective>Accounts>2019 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The similarities between Receipts and payments and income and expenditure account is all, Except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Both accounts follows the principle of double entry </div>", "<div style=\"font-family:Cambria;font-size:17px;\">They are summaries of financial statements </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both include capital items </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both are prepared by non-profit making concern</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both include capital items is not one of the similarities between receipts and payments and income and expenditure account. Receipts and payments account include capital and revenue items while only revenue are recorded in income and expenditure account. <br/>  <br/> </div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS"}, {"id": "objective>Accounts>2019 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> <br/> Equipment <br/> Motor Vehicle <br/> Loan <br/> Creditors <br/> Sub in advance <br/> Sub in arrears</td><td style=\"border:1px solid black;text-align:center;\">₦ <br/> 10,000 <br/> 15,000 <br/> 4,500 <br/> 3,000 <br/> 150 <br/> 3500</td></tr></table></div> <br/> What is the accumulated fund?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦14,150</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20,850</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦21,850</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦14,200</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Accumulated fund = Assets - liabilities  <br/> 10,000 + 15,000 + 3500 - 4500 + 3000 + 150 <br/> 28,500 - 7650 <br/> ₦20,850</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS"}, {"id": "objective>Accounts>2019 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information to answer this question <br/>  <br/> Payment to creditors ₦12,250 <br/> Creditors at start ₦550 <br/> Creditors at end ₦830 <br/>  <br/> What us the amount of purchase </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦11,970</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦11,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,250</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦12,530</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">=  12,250 + 830 - 550 <br/>  <br/> =  13,080 - 550 <br/>  <br/> =  ₦12,530</div>", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2019 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information to answer this question <br/>  <br/> Payment to creditors ₦12,250 <br/> Creditors at start ₦550 <br/> Creditors at end ₦830 <br/> What is the creditors amount in the balance sheet?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦550</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦12,250</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦12,530</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦830</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The creditors amount in the balance sheet is the amount that the company owes to its creditors at the end of the period, which is ₦830.</div>", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2019 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the preparation of statement of profit, if the opening capital is greater than closing capital, there will be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between opening and closing capital will give either a profit or loss. <br/> If the opening capital is greater than closing capital then loss and vice versa.</div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : COMPUTATION OF PROFIT"}, {"id": "objective>Accounts>2019 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The manufacturing account is prepared to ascertain </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cost of goods sold </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Finished goods </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The manufacturing account forms an integral part of the revenue account of a manufacturing organization. It is prepared to ascertain the cost of the goods manufactured or to ascertain the amount of any profit on the manufacturing process i.e the cost of production.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2019 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not charged to manufacturing account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Direct expenses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Factory wages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Distribution expenses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Raw materials </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Distribution expenses covers the cost of warehousing, transport, material handling e.t.c. It is a non-manufacturing cost and not part of production cost.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2019 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A machine cost ₦12,500 it will be kept for 4 years and then sold at a scrap value of ₦5,120. Using the diminishing balance method, what is the amount of depreciation for second year?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦5,120</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6,400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦8,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦12,500</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">N &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">Scrapvalue&nbsp;</span><hr size=\"1\" />cost</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">4 &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">5720<hr size=\"1\" />2500</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> 1 - 4 &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">0.4096&nbsp;</span> <br/>  <br/> 1 - 0.8 = 0.2 or 20% <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> <br/> Year 1 20% × 12500</td><td style=\"border:1px solid black;text-align:center;\">₦ <br/> 12,500 <br/> 2,500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> <br/> Year 2 20% × 10,000</td><td style=\"border:1px solid black;text-align:center;\">10,000 <br/> 2000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Estimated value </td><td style=\"border:1px solid black;text-align:center;\">8,000</td></tr></table></div></div>", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION"}, {"id": "objective>Accounts>2019 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An officer that is charged with the responsibility of carrying out investigations on the book of accounts to show the true and fair view is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ministry of Finance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accountant General </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Revenue office </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Auditor General </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Auditor General ensures that all money collected is properly accounted for and that the records comply with the rules and regulations.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING"}, {"id": "objective>Accounts>2019 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The instrument issued by the Minister who authorized an officer to incur expenditure is a/an</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">warrant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget </div>", "<div style=\"font-family:Cambria;font-size:17px;\">imprest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consolidated fund </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A warrant is a legal document issued by a government official authorizing an officer to incur expenditure. It is a form of authorization that allows the officer to spend a certain amount of money for a specific purpose. The other options do not fit the context of the question. A budget is a financial plan for a defined period, an imprest is a cash advance system, and a consolidated fund is a government's main bank account, holding all the public's receipts and making all the payments for government departments.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES"}, {"id": "objective>Accounts>2019 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the objective of maintaining the account of a branch at the head office is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">to access the performance of the branches </div>", "<div style=\"font-family:Cambria;font-size:17px;\">check the excesses of customers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">record charges in shareholdings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">record charges in liabilities </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main objective of maintaining the account of a branch at the head office is to assess the performance of the branches. This allows the head office to monitor the financial performance and operations of each branch, ensuring they are meeting their targets and operating efficiently. The other options do not fit the context of the question. Checking the excesses of customers, recording changes in shareholdings, and recording changes in liabilities are not primary reasons for maintaining branch accounts at the head office.</div>", "topic": "BRANCH ACCOUNTING : INTRODUCTION AND ADVANTAGES"}, {"id": "objective>Accounts>2019 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A company goods sent to branch at invoiced price is ₦30,870 at cost plus 25%. The mark-up is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦20,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6,174 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦10,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Convert mark-up to margin <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">25<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4+1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />5</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Profit</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />5</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">30,870</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">₦6,174</td></tr></table></div></div>", "topic": "BRANCH ACCOUNTING : PRICING METHODS"}, {"id": "objective>Accounts>2019 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The objective of departmentalization is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ensure that departmental managers are adequately monitored </div>", "<div style=\"font-family:Cambria;font-size:17px;\">record transactions for each department for better documentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tackle any recording problem as a result of expansion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaluate the profit of different departments </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The preparation of departmental accounts will show which department is most profitable and may guide in decision making process as to which department must be closed down in some organizations.</div>", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT"}, {"id": "objective>Accounts>2019 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Discount received is apportioned to each department on the basis of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Floor area </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Turnover </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Purchases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Horse power </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Discount received suggested basis of allocation is purchases. It should be noted that the basis of allocation of expenses will depend on the method specified in the examination.</div>", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES"}, {"id": "objective>Accounts>2019 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> <br/> Fixed assets <br/> Liabilities <br/> Current assets</td><td style=\"border:1px solid black;text-align:center;\">₦ <br/> 55,000 <br/> 20,000 <br/> 13,000</td></tr></table></div> <br/> What is the capital?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦88,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦48,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦62,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦55,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The formula to calculate capital is: Capital = Assets - Liabilities.  <br/>  <br/> In this case, the total assets (fixed assets + current assets) is: <br/>  ₦68,000 (₦55,000 + ₦13,000) and the liabilities is ₦20,000.  <br/>  <br/> So, the capital is ₦68,000 - ₦20,000 <br/>  = ₦48,000.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2019 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the limitations of accounting is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it ascertain financial position</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it prevent fraud </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transactions are recorded in monetary terms </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it monitor the progress of the enterprise </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In accounting, all transactions are recorded in monetary terms. There is no other terms of recording transactions except monetary.</div>", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING"}, {"id": "objective>Accounts>2019 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Capital at start was ₦250,000, while capital at the end of the year was ₦400,000. Drawings during the year amounted to ₦15,000. What is the profit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦165,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦635,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦600,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦156,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using the formular <br/> AC + DC + NP - D = CC <br/> Where OC = Opening Capital <br/> AC = Additional capital <br/> NP = Net profit  <br/> D = Drawing <br/> CC = Closing Capital <br/>   <br/> Therefore, <br/> 250,000 + P - 15,000 = 400,000 <br/> P = 400,000 - 250,000 + 15,000 <br/> P = ₦165,000 </div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2019 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bank reconciliation statement compares a bank statement with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cash payment journal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cash receipt journal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Financial statements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cashbook</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To reconcile the same a bank reconciliation statement is prepared. The aim while preparing a bank reconciliation statement is to take either pass book or cash book  balance as the starting point, to add or deduct certain entries and reach the balance of the other book ie, if cash book balance is the starting point then after reconciling we should reach at pass book balance.</div>", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREENMENT BETWEEN CASH BOOK & BANK STATEMENT"}, {"id": "objective>Accounts>2019 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the preparation of account, the owners of the business and the business concerned are treated as:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">partners </div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint venture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same person</div>", "<div style=\"font-family:Cambria;font-size:17px;\">separate legal entities </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The business entity concept state that business is treated as a separate entity from parties having proprietary or economic interest in it.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS"}, {"id": "objective>Accounts>2019 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From the following, determine the value of closing stock using FiFO method. <br/>  <br/> Feb 1 purchased 200 units @ ₦2.00 each <br/> Feb 3 purchased 100 units @ ₦1.00 each <br/> Feb 4 issued 120 units @ ₦5.00 each <br/> Feb 5 purchased 50 units @ ₦3.00 each <br/> Feb 6 issued 100 units @ ₦4.00 each</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦330</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦420</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦230</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦320</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Feb1 : 200 × 2 = <br/> feb 3 : 100 × 1 = </td><td style=\"border:1px solid black;text-align:center;\">400 <br/> 100</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> <br/> Feb 4 : 120 × 2 = </td><td style=\"border:1px solid black;text-align:center;\">500 <br/> (240)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> <br/> Feb 5 : 50 × 3</td><td style=\"border:1px solid black;text-align:center;\">260 <br/> 150</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> <br/> Feb 6 : 80 × 2 =</td><td style=\"border:1px solid black;text-align:center;\">410 <br/> (160)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> <br/> 20 × 1</td><td style=\"border:1px solid black;text-align:center;\">250 <br/> (20)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">100</td><td style=\"border:1px solid black;text-align:center;\">230</td></tr></table></div> <br/> The value of closing stock is ₦230</div>", "topic": "STOCK VALUATION : MEANING OF STOCK VALUATION AND METHODS"}, {"id": "objective>Accounts>2019 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sent B a cheque for ₦2000 to provide him with friends. They agreed to share profits in ratio 3 : 2 and settlement is by cheque. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> <br/>  <br/> Sales <br/> Advert <br/> Wages  <br/> Purchases</td><td style=\"border:1px solid black;text-align:center;\">A <br/> ₦ <br/> 3200 <br/> 327 <br/> 85 <br/> 1600</td><td style=\"border:1px solid black;text-align:center;\">B <br/> ₦ <br/> 2100 <br/> 463 <br/> 70 <br/> 1100</td></tr></table></div> <br/> The profit and loss in joint venture with B account in the ledger of A.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦1000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦900</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦993</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦883</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The amount ₦993 is derived when a memorandum joint venture is calculated as : <br/> <img src=\"2019 Model II/img2.png\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> In the ledger of A Joint Venture with B account <br/> <img src=\"2019 Model II/img3.png\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>2019 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following documents is NOT required for the formation of a company?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Memorandum of Association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Articles of Association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Certificate of Incorporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shareholder Agreement</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Shareholder Agreement is not a mandatory document for the formation of a company. The Memorandum of Association, Articles of Association, and Certificate of Incorporation are essential documents required by law for the registration and formation of a company.</div>", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY"}, {"id": "objective>Accounts>2019 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Memorandum of Association must state the company's:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Name and registered office</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Financial statements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Board of Directors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Annual report</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Memorandum of Association is a legal document that outlines the company's name, registered office, objectives, and the scope of its activities. It does not include financial statements, board of directors, or annual reports, which are covered in other documents.</div>", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY"}, {"id": "objective>Accounts>2019 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best describes the primary function of a financial system?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">To regulate the stock market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To facilitate the flow of funds between savers and borrowers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To provide insurance services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To manage government budgets</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary function of a financial system is to facilitate the flow of funds between savers and borrowers, enabling efficient allocation of resources and promoting economic growth. This involves various financial institutions and markets that connect those who have surplus funds with those who need funds for investment or consumption.</div>", "topic": "FINANCIAL SYSTEM : MEANING, FUNCTIONS AND FEATURES"}];
